      ...input,
      ownerId,
      createdBy,
      agencyCode: input.agencyCode,
      code,
    };

    return this.customerRepo.insert(payload);
  }

  private recalcCancellationBooking(prices: PriceSetting[]): CancellationPolicy {
    let policy = new CancellationPolicy();
    policy.type = CancellationType.NO_CANCELLATION;

    // Định nghĩa độ ưu tiên cho các loại huỷ
    const cancellationPriority: Record<CancellationType, number> = {
      [CancellationType.NO_CANCELLATION]: 3,
      [CancellationType.CANCELLATION_CHARGE]: 2,
      [CancellationType.FREE_CANCELLATION]: 1,
    };

    let cancellations = prices.map(e => ({
      type: e.condition,
      time: e.cancellationPeriod,
      unit: e.cancellationPeriodUnitTime,
      cancellationFee: e.amount,
      feeType: e.unitType,
      seasonType: e.season?.type,
      priority: cancellationPriority[e.condition] ?? 0,
    })).filter(c => c != null);

    // Kiểm tra xem có EVENT không
    const hasAnyEvent = cancellations.some(opt => opt.seasonType === 'EVENT');

    if (hasAnyEvent) {
      // Chỉ giữ EVENT options, loại bỏ TẤT CẢ SEASON
      cancellations = cancellations.filter(opt => opt.seasonType === 'EVENT');
    }

    // Sắp xếp theo độ ưu tiên
    cancellations.sort((a, b) => {
      // Sắp xếp theo độ ưu tiên giảm dần (priority cao hơn lên trước)
      if (a.priority !== b.priority) {
        return b.priority - a.priority;
      }

      // Nếu priority bằng nhau, chọn theo amount lớn hơn
      const aFee = a.cancellationFee ?? 0;
      const bFee = b.cancellationFee ?? 0;
      if (aFee !== bFee) {
        return bFee - aFee;
      }

      // Nếu vẫn bằng nhau, sắp xếp theo time
      if (a.time === b.time) {
        return 0;
      }
      return a.time! < b.time! ? -1 : 1;
    });

    return cancellations?.[0] || policy;
  }

